class Solution:
    def countBirthdayGifts(self, month, employees, birthdays):
        # 哈希表：记录每个员工最后一次录入的生日月份
        last_month = {}

        # 遍历所有录入信息，后出现的同名员工会覆盖前面的记录
        for i in range(len(employees)):
            name = employees[i]
            birthday = birthdays[i]

            # 按 '/' 分割，取中间部分作为月份
            m = int(birthday.split('/')[1])
            last_month[name] = m

        # 统计最后生日月份等于目标月份的员工个数
        ans = 0
        for m in last_month.values():
            if m == month:
                ans += 1

        return ans
```

