import java.util.HashMap;
import java.util.List;
import java.util.Map;

class Solution {
    public int countBirthdayGifts(int month, List<String> employees, List<String> birthdays) {
        // 哈希表：记录每个员工最后一次录入的生日月份
        Map<String, Integer> lastMonth = new HashMap<>();

        // 遍历所有录入信息，后面的同名员工会覆盖前面的记录
        for (int i = 0; i < employees.size(); i++) {
            String name = employees.get(i);
            String birthday = birthdays.get(i);

            // 按 "/" 分割，取月份
            String[] parts = birthday.split("/");
            int m = Integer.parseInt(parts[1]);

            lastMonth.put(name, m);
        }

        // 统计目标月份的人数
        int ans = 0;
        for (int m : lastMonth.values()) {
            if (m == month) {
                ans++;
            }
        }

        return ans;
    }
}
