```cpp
#include <vector>
#include <string>
#include <unordered_map>
using namespace std;

class Solution {
public:
    int countBirthdayGifts(int month, vector<string>& employees, vector<string>& birthdays) {
        // 哈希表：记录每个员工最后一次录入的生日月份
        unordered_map<string, int> lastMonth;

        // 遍历所有录入信息，后面的同名员工会覆盖前面的记录
        for (int i = 0; i < employees.size(); i++) {
            string name = employees[i];
            string birthday = birthdays[i];

            // 解析月份：格式为 Year/Month/Day
            int firstSlash = birthday.find('/');
            int secondSlash = birthday.find('/', firstSlash + 1);
            int m = stoi(birthday.substr(firstSlash + 1, secondSlash - firstSlash - 1));

            lastMonth[name] = m;
        }

        // 统计目标月份的人数
        int ans = 0;
        for (auto& entry : lastMonth) {
            if (entry.second == month) {
                ans++;
            }
        }

        return ans;
    }
};
