    for (let i = 0; i < employees.length; i++) {
        const m = parseInt(birthdays[i].split('/')[1], 10);
        lastMonth[employees[i]] = m;
    }
    // 统计生日月份等于目标月份的员工数
    let cnt = 0;
    for (const m of Object.values(lastMonth)) {
        if (m === month) cnt++;
    }
    return cnt;
};
